var raw = $input.first().json.choices[0].message.content.trim();
var ids = $input.first().json.ids;

var digest;
try {
  digest = JSON.parse(raw);
} catch(e) {
  return [{ json: { message: 'Erreur de parsing du digest.', ids: ids } }];
}

var semaine = new Date().toLocaleDateString('fr-FR');
var messages = [];

// En-tête toujours dans le premier message
var header = '📰 <b>Digest Newsletters — ' + semaine + '</b>\n' +
  '📬 ' + digest.nb_newsletters + ' newsletter(s) analysée(s)\n' +
  '\n⭐ <b>À retenir :</b> ' + digest.a_retenir + '\n';

var current = header;

for (var i = 0; i < digest.themes.length; i++) {
  var theme = digest.themes[i];
  var themeBlock = '\n' + theme.emoji + ' <b>' + theme.nom + '</b>\n';

  for (var j = 0; j < theme.points.length; j++) {
    var point = theme.points[j];
    var tag = point.actionnable ? ' 🎯' : '';
    themeBlock += '\n• <b>' + point.titre + '</b>' + tag + '\n';
    themeBlock += '  ' + point.detail + '\n';
    themeBlock += '  <i>— ' + point.source + '</i>\n';
  }

  // Si ajout dépasse 4000 chars → nouveau message
  if ((current + themeBlock).length > 4000) {
    messages.push(current);
    current = themeBlock;
  } else {
    current += themeBlock;
  }
}

if (current.length > 0) {
  messages.push(current);
}

return messages.map(function(msg, idx) {
  return {
    json: {
      message: msg,
      ids: idx === 0 ? ids : []  // ids seulement sur le premier item
    }
  };
});

var bloc = $input.first().json.bloc;
var nb = $input.first().json.nb;

var body = {
  model: "deepseek-v4-flash",
  temperature: 0.3,
  messages: [
    {
      role: "system",
      content: "Tu es un assistant de veille informationnelle. Tu analyses des newsletters et extrais uniquement les informations vraiment intéressantes ou actionnables. Tu ignores le contenu promotionnel, les annonces sans valeur, et les redites. Tu regroupes les insights par grande thématique. Tu réponds UNIQUEMENT en JSON valide sans backticks."
    },
    {
      role: "user",
      content: "Voici " + nb + " newsletters reçues cette semaine :\n\n" + bloc + "\n\nAnalyse-les et réponds avec ce JSON :\n{\"themes\":[{\"nom\":\"Nom du thème\",\"emoji\":\"emoji\",\"points\":[{\"titre\":\"titre court\",\"detail\":\"2-3 phrases\",\"source\":\"newsletter source\",\"actionnable\":true}]}],\"a_retenir\":\"point le plus important en 1 phrase\",\"nb_newsletters\":" + nb + "}"
    }
  ]
};

return [{ json: { body: body } }];

// Récupère les IDs stockés dans le nœud de préparation
var ids = $('Code JS - Prépare').first().json.ids;

// Retourne un item par ID pour que Gmail Add Label boucle
return ids.map(function(id) {
  return { json: { emailId: id } };
});

const emails = $input.all();

// Remplace par l'ID réel de ton label digest-done
var DIGEST_DONE_LABEL = 'Label_853856882183347882';

const stripHtml = function(html) {
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&apos;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&shy;/g, '')        // ← tiret conditionnel
    .replace(/&zwnj;/g, '')       // ← espace sans jonction
    .replace(/&#[0-9]+;/g, '')    // ← tous les codes HTML numériques
    .replace(/[\u200c\u200b\u00ad\u0083\u008d]/g, '')  // ← caractères invisibles unicode
    .replace(/͏/g, '')             // ← U+034F combining grapheme joiner
    .replace(/\s{2,}/g, ' ')
    .trim();
};

const newsletters = emails
  .filter(function(e) {
    var labels = e.json.labelIds || [];
    return !labels.includes(DIGEST_DONE_LABEL);
  })
  .map(function(e) {
    var from = e.json.from;
    var expediteur = (from && from.value && from.value[0])
      ? (from.value[0].name || from.value[0].address)
      : 'Inconnu';

    return {
      id:         e.json.id,
      expediteur: expediteur,
      sujet:      e.json.subject || '',
      contenu:    stripHtml(e.json.html || e.json.text || '').slice(0, 2000)
    };
  });

if (newsletters.length === 0) {
  return [{ json: { hasNewsletters: false } }];
}

const bloc = newsletters.map(function(n, i) {
  return '--- NEWSLETTER #' + (i + 1) + ' ---\n' +
    'De : ' + n.expediteur + '\n' +
    'Sujet : ' + n.sujet + '\n' +
    'Contenu : ' + n.contenu;
}).join('\n\n');

return [{
  json: {
    hasNewsletters: true,
    bloc: bloc,
    ids: newsletters.map(function(n) { return n.id; }),
    nb: newsletters.length
  }
}];
